-- ═══════════════════════════════════════════════════════════════════
-- CodeQuest · Migración 025 — Redes y Sistemas · Módulo 6: Routing y segmentación
-- ═══════════════════════════════════════════════════════════════════
-- 6 lecciones + examen de región (43 bloques).
-- Incluye el diagrama del temario: la red de la clínica SEGMENTADA
-- (zonas: administración, servidores, DMZ, invitados/IoT) con
-- NetworkDiagram data-driven — el diagrama de arquitectura que pidió
-- Karen, reutilizable en los cursos de defensa.
-- Incluye la nota ética de Wi-Fi: capturar tráfico SOLO en redes
-- propias o con autorización — prepara el lab de Wireshark del M7.
-- Cosecha las semillas: segmentación (M3), el cruce vigilado, el
-- candado por capas (M2/M4), la tríada en el firewall (M5).
-- Reglas de contenido: sin tecnología interna de la plataforma;
-- quizzes autocontenidos o con términos técnicos.
-- OJO: Redes está PUBLICADO — correr esta migración hace el M6
-- visible a los usuarios AL INSTANTE.
-- Idempotente: borra y recrea las lecciones de ESTE módulo.
-- Ejecutar DESPUÉS de 006.
-- ═══════════════════════════════════════════════════════════════════

-- Limpia el módulo (cascade borra sus content_blocks)
delete from public.lessons
where module_id = (
  select m.id
  from public.modules m
  join public.courses c on c.id = m.course_id
  where c.slug = 'redes-y-sistemas' and m.slug = 'm06-routing-y-segmentacion'
);

-- ── Lecciones del módulo ──────────────────────────────────────────────
insert into public.lessons (module_id, slug, title, kind, xp, sort_order)
