from public.modules m
join public.courses c on c.id = m.course_id,
     (values
       ('m06-l01-vlans',           'Switching y VLANs: separar sin recablear', 'leccion', 20, 1),
       ('m06-l02-routing',         'Routing: cómo se encuentra el camino',     'leccion', 20, 2),
       ('m06-l03-firewalls',       'Firewalls: el vigilante del cruce',        'leccion', 20, 3),
       ('m06-l04-clinica-segmentada','La red de la clínica, segmentada',       'leccion', 20, 4),
       ('m06-l05-vpn',             'VPN: el túnel cifrado',                    'leccion', 20, 5),
       ('m06-l06-wifi',            'Wi-Fi: seguridad en el aire',              'leccion', 20, 6),
       ('m06-x01-examen',          'Examen: Routing y segmentación',           'examen',  40, 7)
     ) as v(slug, title, kind, xp, ord)
where c.slug = 'redes-y-sistemas' and m.slug = 'm06-routing-y-segmentacion';

-- ═════════════════════════════════════════════════════════════════════
-- L01 · Switching y VLANs
-- ═════════════════════════════════════════════════════════════════════
insert into public.content_blocks (lesson_id, sort_order, kind, payload)
select l.id, v.ord, v.kind, v.payload::jsonb
from public.lessons l
join public.modules m on m.id = l.module_id
join public.courses c on c.id = m.course_id,
(values
  (1, 'texto', $j${"title":"El problema: separar sin comprar switches","body":"El módulo 3 te vendió la idea de partir la red en subredes — administración por un lado, invitados por otro. Pero ¿cómo se hace FÍSICAMENTE? ¿Un switch para cada subred, con su propio cableado? Carísimo y rígido. La respuesta elegante es la VLAN (Virtual LAN): redes LÓGICAS separadas conviviendo dentro del MISMO switch físico. Cada puerto del switch se asigna a una VLAN — los puertos 1 a 8 son la VLAN 10 (administración), los 9 a 16 la VLAN 20 (invitados) — y el switch trata cada grupo como una red aislada: una trama de la VLAN 10 JAMÁS aparece en un puerto de la VLAN 20, aunque viajen por el mismo aparato. Mismo hardware, fronteras de software: separar sin recablear."}$j$),
  (2, 'texto', $j${"title":"La regla de oro de las VLANs","body":"Grábate la consecuencia, porque define el diseño de toda red empresarial: dos VLANs NO se hablan directamente — ni compartiendo switch, ni compartiendo edificio. Son redes distintas de verdad: para que un paquete cruce de la VLAN de administración a la de servidores tiene que pasar por un ROUTER (o un switch de capa 3, que es un switch con alma de router) — exactamente la frontera 'dentro vs fuera' del módulo 1, ahora fabricada a voluntad. Y esa obligación de cruzar por un punto único es una BENDICIÓN para la seguridad: en el cruce se puede mirar, filtrar y registrar todo (la tríada del módulo 5 tomando notas). La clínica del diagrama de este módulo está construida entera sobre esta regla."}$j$),
  (3, 'quiz', $j${"variant":"multiple_choice","prompt":"En términos técnicos, ¿qué es una VLAN?","options":["Un switch mucho más rápido que los demás","Una red doméstica que funciona sin cables","Una red lógica dentro de un switch físico, aislada","Una marca comercial conocida de router de red"],"correctIndex":2,"feedback":{"correct":"Correcto. Mismo hardware, fronteras de software: la VLAN 10 y la VLAN 20 no se ven, aunque compartan aparato.","incorrect":"VLAN = LAN virtual: redes lógicas separadas conviviendo en el mismo switch físico, cada puerto asignado a la suya."}}$j$),
  (4, 'quiz', $j${"variant":"multiple_choice","prompt":"Una trama necesita ir de la VLAN de administración a la VLAN de servidores, ambas en el mismo switch. ¿Qué necesita el viaje?","options":["Nada especial: los dos comparten el mismo switch físico","Con un cable de red algo más corto","Cambiando la contraseña del Wi-Fi","Pasando por un router: son redes distintas, ahí se filtra"],"correctIndex":3,"feedback":{"correct":"Correcto. La regla de oro: entre VLANs siempre hay un router en el camino — y ese cruce único es donde vive la seguridad.","incorrect":"Dos VLANs no se hablan directo aunque compartan hardware: el cruce pasa por un router, que puede vigilar y filtrar."}}$j$),
  (5, 'resumen', $j${"title":"Resumen — VLANs","points":["VLAN = red lógica dentro del switch físico: cada puerto asignado a su grupo, grupos aislados entre sí.","Separar sin recablear: las subredes del módulo 3, fabricadas por software.","Regla de oro: dos VLANs solo se comunican a través de un router (o switch de capa 3).","El cruce único es la bendición de seguridad: ahí se mira, se filtra y se registra.","Toda red empresarial seria — la clínica incluida — se construye sobre esta regla."]}$j$)
) as v(ord, kind, payload)
where c.slug = 'redes-y-sistemas' and l.slug = 'm06-l01-vlans';

-- ═════════════════════════════════════════════════════════════════════
-- L02 · Routing: cómo se encuentra el camino
-- ═════════════════════════════════════════════════════════════════════
insert into public.content_blocks (lesson_id, sort_order, kind, payload)
select l.id, v.ord, v.kind, v.payload::jsonb
from public.lessons l
join public.modules m on m.id = l.module_id
join public.courses c on c.id = m.course_id,
(values
  (1, 'texto', $j${"title":"Nadie conoce el camino completo","body":"Cuando hiciste tracert en el módulo 3 viste una docena de routers entre tú y el destino. Aquí está el secreto de cómo se organiza ese viaje: NINGÚN router conoce el camino completo. Cada uno tiene una TABLA DE RUTAS — una lista de 'para llegar a tal red, entrega al vecino tal' — y toma UNA sola decisión: el SIGUIENTE SALTO. Recibe el paquete, abre el sobre hasta la capa 3 (el encapsulamiento del módulo 2), lee la IP de destino, consulta su tabla, y lo pasa al vecino que esté más cerca del destino. El siguiente router repite. El camino completo no existe en ningún lado: EMERGE de miles de decisiones locales — así internet funciona sin dueño ni mapa central, y así sobrevive cuando un tramo se cae: las tablas se actualizan y los paquetes fluyen por otro lado."}$j$),
  (2, 'texto', $j${"title":"La ruta por defecto: 'todo lo demás, por aquí'","body":"¿Y si la tabla no tiene una entrada para el destino? Para eso existe la RUTA POR DEFECTO: 'todo lo que no conozco, va por esta puerta'. Tu laptop la usa a cada momento: su tabla es diminuta — 'mi propia red, directo; TODO lo demás, al gateway' — y ese gateway es la puerta de enlace que conoces desde el módulo 1, ahora con su nombre técnico completo. Los routers de la clínica igual: conocen sus subredes internas al detalle, y lo que va a internet sale por la ruta por defecto hacia el proveedor. La jerarquía es elegante: conocimiento detallado de lo cercano, una sola flecha genérica hacia lo lejano."}$j$),
  (3, 'quiz', $j${"variant":"multiple_choice","prompt":"En términos de routing, ¿qué decisión toma cada router cuando le llega un paquete?","options":["Solo el siguiente salto: entrega al vecino más cercano","Calcula el camino completo hasta el destino final","Le pregunta directamente al usuario qué hacer","Lo envía a todos sus vecinos al mismo tiempo"],"correctIndex":0,"feedback":{"correct":"Correcto. Nadie tiene el mapa completo: cada router decide un salto, y el viaje emerge — por eso internet no necesita dueño.","incorrect":"Cada router decide solo el siguiente salto según su tabla. El camino completo no existe en ningún lado: emerge salto a salto."}}$j$),
  (4, 'quiz', $j${"variant":"multiple_choice","prompt":"La tabla de rutas de tu laptop cabe en dos líneas: 'mi red, directo' y una segunda entrada donde va TODO lo demás. Esa segunda entrada se llama:","options":["Una ruta secreta que ningún otro equipo conoce","La ruta por defecto: lo que no conozco sale por aquí","Una tabla de respaldo por si algo falla","El servidor de DNS de tu proveedor"],"correctIndex":1,"feedback":{"correct":"Correcto. La puerta de enlace del módulo 1, con su nombre técnico completo: el destino de la ruta por defecto.","incorrect":"Es la ruta por defecto: el 'todo lo demás' que apunta al gateway — conocimiento fino de lo cercano, una flecha genérica a lo lejano."}}$j$),
  (5, 'resumen', $j${"title":"Resumen — Routing","points":["Ningún router conoce el camino completo: cada uno decide solo el SIGUIENTE salto con su tabla de rutas.","El viaje emerge de miles de decisiones locales: internet funciona sin mapa ni dueño central.","Si un tramo cae, las tablas se actualizan y el tráfico fluye por otro lado: resiliencia de fábrica.","La RUTA POR DEFECTO: 'todo lo que no conozco, por esta puerta' — en tu equipo, esa puerta es el gateway.","El tracert del módulo 3 era esto en vivo: la cadena de decisiones, salto a salto."]}$j$)
) as v(ord, kind, payload)
where c.slug = 'redes-y-sistemas' and l.slug = 'm06-l02-routing';

-- ═════════════════════════════════════════════════════════════════════
-- L03 · Firewalls: el vigilante del cruce
-- ═════════════════════════════════════════════════════════════════════
insert into public.content_blocks (lesson_id, sort_order, kind, payload)
select l.id, v.ord, v.kind, v.payload::jsonb
from public.lessons l
join public.modules m on m.id = l.module_id
join public.courses c on c.id = m.course_id,
(values
  (1, 'texto', $j${"title":"Reglas en la puerta","body":"Si las VLANs obligan a todo cruce a pasar por un punto único, el FIREWALL es el vigilante apostado en ese punto: examina cada paquete que intenta cruzar y lo PERMITE o lo BLOQUEA según una lista de REGLAS. Una regla habla el idioma que ya dominas: origen (IP o zona), destino, puerto/protocolo, y el veredicto. Ejemplos de la clínica: 'PERMITIR administración → servidor de expedientes por el 443' · 'BLOQUEAR invitados → cualquier red interna'. Y el principio que ordena todo: DENEGAR POR DEFECTO — lo que ninguna regla permite explícitamente, se bloquea. La lista de permitidos es corta y pensada; lo demás, muro. ¿Te suena? Es el mínimo privilegio del módulo 5, aplicado al tráfico. Y cada decisión del vigilante queda ANOTADA: los logs del firewall — tríada incluida — son oro forense."}$j$),
  (2, 'texto', $j${"title":"Qué bloquea de verdad (y qué no)","body":"Un firewall filtra por DIRECCIONES y PUERTOS: quién habla con quién y por qué puerta. Lo que NO hace es leer intenciones. Si el puerto 443 hacia internet está permitido (y debe estarlo: es la web), por ahí pasa el tráfico legítimo… y también la conexión hacia un sitio de phishing con su candado válido (módulo 4), o el malware que un empleado ejecutó y que llama a casa por ese mismo puerto permitido. El firewall tampoco ve lo cifrado por dentro: sobres sí, cartas no. Moraleja profesional: el firewall es UNA capa — imprescindible, no suficiente. Se complementa con los permisos del módulo 5, el criterio anti-phishing del módulo 4 y la vigilancia de logs. La seguridad en capas no es un eslogan: es que ninguna capa sola basta."}$j$),
  (3, 'quiz', $j${"variant":"multiple_choice","prompt":"¿Qué enuncia el principio 'denegar por defecto' de un firewall?","options":["Que absolutamente todo se bloquea, sin excepción","Que solo se deniega el tráfico durante la noche","Lo que ninguna regla permite explícitamente, se bloquea","Que las reglas se escriben totalmente al azar"],"correctIndex":2,"feedback":{"correct":"Correcto. El mínimo privilegio aplicado al tráfico: permitido explícito, bloqueado lo demás.","incorrect":"Denegar por defecto: solo cruza lo explícitamente permitido. Es la versión de red del mínimo privilegio."}}$j$),
  (4, 'quiz', $j${"variant":"multiple_choice","prompt":"Un empleado ejecuta un malware que roba datos enviándolos por el puerto 443 (permitido para navegar). ¿Por qué el firewall no lo detuvo?","options":["Porque el firewall estaba simplemente apagado","Porque el puerto 443 no se puede bloquear nunca","Porque los firewalls no funcionan bien durante el día laboral","El firewall filtra puertos, no intenciones: la puerta era legal"],"correctIndex":3,"feedback":{"correct":"Correcto. El vigilante revisa la puerta, no el alma: canal permitido = tráfico que pasa. Ninguna capa sola basta.","incorrect":"El firewall vio tráfico saliendo por un puerto permitido — su regla se cumplió. Las intenciones se cazan con otras capas: permisos, criterio, logs."}}$j$),
  (5, 'resumen', $j${"title":"Resumen — Firewalls","points":["El firewall vigila el cruce: permite o bloquea cada paquete según reglas de origen, destino y puerto.","DENEGAR POR DEFECTO: lo no permitido explícitamente, se bloquea — mínimo privilegio para el tráfico.","Filtra direcciones y puertos, NO intenciones: el phishing y el malware por canales permitidos lo cruzan.","No ve dentro de lo cifrado: sobres sí, cartas no.","Es UNA capa imprescindible, no suficiente: permisos + criterio + logs completan la defensa."]}$j$)
) as v(ord, kind, payload)
where c.slug = 'redes-y-sistemas' and l.slug = 'm06-l03-firewalls';

-- ═════════════════════════════════════════════════════════════════════
-- L04 · La red de la clínica, segmentada (diagrama del temario)
-- ═════════════════════════════════════════════════════════════════════
insert into public.content_blocks (lesson_id, sort_order, kind, payload)
select l.id, v.ord, v.kind, v.payload::jsonb
from public.lessons l
join public.modules m on m.id = l.module_id
join public.courses c on c.id = m.course_id,
(values
  (1, 'texto', $j${"title":"Zonas por nivel de confianza","body":"Hora de armar la red completa de la clínica con todas las piezas del curso. El principio de diseño: agrupar por NIVEL DE CONFIANZA, en zonas separadas (VLANs/subredes) con el firewall vigilando cada cruce. ADMINISTRACIÓN: recepción y consultorios — confianza alta, acceso a expedientes. SERVIDORES: los expedientes — la joya de la corona, la zona más protegida: solo administración llega, y solo por los puertos del oficio. DMZ (zona desmilitarizada): lo que DEBE estar expuesto a internet — la web pública de citas — vive aislado del resto: si un atacante la compromete, queda atrapado en una isla sin puente a los expedientes. INVITADOS e IoT: el Wi-Fi de pacientes y los monitores médicos conectados — confianza mínima: solo salida a internet, cero acceso interno. Explora el diagrama: toca cada zona, cada equipo y cada cruce."}$j$),
  (2, 'diagrama', $j${"title":"La clínica segmentada","component":"NetworkDiagram","props":{"label":"Red empresarial · zonas por nivel de confianza","ancho":520,"alto":400,"grupos":[{"id":"admin","x":14,"y":200,"w":156,"h":180,"titulo":"Administración","descripcion":"Confianza alta: recepción y consultorios. Es la ÚNICA zona con permiso de llegar a los expedientes — y solo por los puertos del oficio."},{"id":"serv","x":182,"y":200,"w":156,"h":84,"titulo":"Servidores","descripcion":"La joya de la corona: los expedientes. La zona más cerrada de la red — nadie llega salvo administración, y el firewall registra cada cruce."},{"id":"dmz","x":182,"y":296,"w":156,"h":84,"titulo":"DMZ","descripcion":"Zona desmilitarizada: lo que DEBE estar expuesto a internet vive aquí, aislado. Si la web cae en manos enemigas, el atacante queda en una isla sin puente al resto."},{"id":"inv","x":350,"y":200,"w":156,"h":180,"titulo":"Invitados · IoT","descripcion":"Confianza mínima: el Wi-Fi de pacientes y los monitores conectados. Solo salida a internet — cero rutas hacia las zonas internas."}],"nodos":[{"id":"internet","x":170,"y":10,"w":180,"h":36,"titulo":"Internet","subtitulo":"la red de redes","descripcion":"Todo lo de fuera. Para la clínica: confianza CERO — todo lo que entra o sale se examina en el firewall."},{"id":"fw","x":170,"y":88,"w":180,"h":48,"titulo":"Firewall · Router","subtitulo":"todos los cruces","tag":"el cruce","descripcion":"El corazón del diseño: TODOS los cruces entre zonas (y hacia internet) pasan por aquí. Reglas con denegación por defecto, y cada decisión anotada en el log — la tríada tomando notas."},{"id":"recepcion","x":28,"y":226,"w":128,"h":40,"titulo":"Recepción","subtitulo":"citas y admisión","descripcion":"Clientes de confianza alta: consultan y escriben expedientes a través del cruce vigilado."},{"id":"consultorios","x":28,"y":300,"w":128,"h":40,"titulo":"Consultorios","subtitulo":"médicos","descripcion":"Los médicos consultan expedientes desde su zona: mismo permiso que recepción, mismo cruce vigilado."},{"id":"expedientes","x":196,"y":226,"w":128,"h":40,"titulo":"Expedientes","subtitulo":"servidor interno","descripcion":"El servidor con los datos de pacientes. Su regla de acceso: SOLO desde administración, SOLO por los puertos del oficio, TODO registrado."},{"id":"web","x":196,"y":322,"w":128,"h":40,"titulo":"Web de citas","subtitulo":"expuesta a internet","descripcion":"El servidor público (el de la DMZ): recibe visitas de internet por el 443. Si lo comprometen, no hay ruta de aquí a los expedientes — para eso existe la DMZ."},{"id":"wifi","x":364,"y":226,"w":128,"h":40,"titulo":"Wi-Fi pacientes","subtitulo":"sala de espera","descripcion":"Los teléfonos de los pacientes: internet para la espera, y NADA más. Sin rutas hacia dentro."},{"id":"iot","x":364,"y":300,"w":128,"h":40,"titulo":"Monitores médicos","subtitulo":"IoT","descripcion":"Equipos conectados (monitores, bombas): útiles y DIFÍCILES de parchear — por eso viven en la zona de confianza mínima, lejos de todo."}],"enlaces":[{"de":"internet","a":"fw","tipo":"doble","etiqueta":"WAN","descripcion":"La única puerta al exterior: todo lo que entra o sale de la clínica cruza el firewall."},{"de":"fw","a":"recepcion","descripcion":"Administración cruza hacia servidores e internet según las reglas — siempre a través del vigilante."},{"de":"fw","a":"expedientes","etiqueta":"solo admin","descripcion":"La regla estrella: PERMITIR administración → expedientes (puertos del oficio). Todo lo demás hacia esta zona: denegado por defecto."},{"de":"fw","a":"web","etiqueta":"DMZ","descripcion":"Internet puede visitar la web (443)… y la web NO puede iniciar conexiones hacia las zonas internas: la isla."},{"de":"fw","a":"wifi","etiqueta":"solo internet","descripcion":"Invitados e IoT: salida a internet permitida, CERO rutas hacia administración, servidores o DMZ."}],"hint":"Toca cada zona (marcos punteados), cada equipo y cada cruce del firewall."},"caption":"Cuatro zonas por nivel de confianza, un solo vigilante en todos los cruces, denegación por defecto. Este plano — con otros nombres — es el de casi toda red empresarial seria."}$j$),
  (3, 'quiz', $j${"variant":"multiple_choice","prompt":"La web pública de una clínica vive en la DMZ y no junto al servidor de expedientes. ¿Qué lógica de diseño hay detrás?","options":["Lo expuesto se aísla: si cae la web, queda en una isla","Porque la zona DMZ tiene un internet más rápido","Porque los servidores no caben todos juntos","Porque es un requisito meramente estético"],"correctIndex":0,"feedback":{"correct":"Correcto. La DMZ asume que lo expuesto PUEDE caer — y diseña para que esa caída no toque la joya de la corona.","incorrect":"La DMZ es la isla de lo expuesto: internet puede visitarla, pero desde ella no hay puente hacia las zonas internas."}}$j$),
  (4, 'quiz', $j${"variant":"multiple_choice","prompt":"Un paciente conectado al Wi-Fi de la sala de espera intenta acceder al servidor de expedientes. Según el diseño segmentado, ¿qué ocurre?","options":["Accede, siempre que conozca la contraseña del Wi-Fi","El firewall lo bloquea: no hay regla que permita el cruce","Puede acceder solo en horario de visitas","Depende del modelo de su teléfono móvil"],"correctIndex":1,"feedback":{"correct":"Correcto. La entrevista del módulo 3, respondida con arquitectura: la contraseña decide quién entra; la segmentación decide a dónde llega.","incorrect":"Invitados → expedientes no está permitido por ninguna regla: denegado por defecto. Entrar al Wi-Fi no da rutas hacia dentro."}}$j$),
  (5, 'resumen', $j${"title":"Resumen — La clínica segmentada","points":["Diseño por NIVEL DE CONFIANZA: administración (alta), servidores (joya de la corona), DMZ (expuesto y aislado), invitados/IoT (mínima).","Todos los cruces pasan por el firewall: reglas explícitas + denegación por defecto + registro.","La DMZ asume que lo expuesto puede caer: la web comprometida es una isla sin puente a los expedientes.","Invitados e IoT: solo salida a internet — el Wi-Fi de la sala de espera jamás toca un expediente.","Este plano es el de casi toda red empresarial: apréndelo aquí y lo reconocerás en todas partes."]}$j$)
) as v(ord, kind, payload)
where c.slug = 'redes-y-sistemas' and l.slug = 'm06-l04-clinica-segmentada';

-- ═════════════════════════════════════════════════════════════════════
-- L05 · VPN: el túnel cifrado
-- ═════════════════════════════════════════════════════════════════════
insert into public.content_blocks (lesson_id, sort_order, kind, payload)
select l.id, v.ord, v.kind, v.payload::jsonb
from public.lessons l
join public.modules m on m.id = l.module_id
join public.courses c on c.id = m.course_id,
(values
  (1, 'texto', $j${"title":"Estar dentro, estando fuera","body":"El técnico de la clínica trabaja hoy desde casa y necesita entrar al servidor de expedientes — que, por diseño, SOLO acepta conexiones desde la zona de administración. ¿Cómo? Con una VPN (Virtual Private Network): un TÚNEL CIFRADO que se tiende por encima de internet entre su equipo y la red de la clínica. Al conectarla, su laptop recibe una IP interna y se comporta como si estuviera enchufada dentro — todo su tráfico hacia la clínica viaja cifrado a través del túnel, ilegible para el camino (el espíritu de TLS y SSH, aplicado a la red entera). El firewall trata al túnel como un cruce más: autenticado, con reglas y registrado. El mismo mecanismo une SEDES: dos clínicas de la misma red conectadas por un túnel permanente, como si un cable invisible cruzara la ciudad."}$j$),
  (2, 'texto', $j${"title":"Lo que una VPN promete (y el matiz comercial)","body":"Precisión de vocabulario, porque la palabra se usa para dos cosas distintas. La VPN CORPORATIVA — la de esta lección — extiende una red privada: te mete DENTRO de la red de tu organización a través del túnel. Las VPN COMERCIALES (las de los anuncios) usan la misma tecnología con otro fin: tu tráfico viaja cifrado hasta los servidores del proveedor y sale a internet desde ahí. Sirven para que la red local que estés usando (el Wi-Fi del aeropuerto) no vea tu tráfico… pero fíjate en el matiz: no elimina la confianza, la MUEVE — ahora quien puede ver tu tráfico de salida es el proveedor de la VPN. No es anonimato mágico ni seguridad total: es elegir en quién confías. Criterio, como siempre, sobre marketing."}$j$),
  (3, 'quiz', $j${"variant":"multiple_choice","prompt":"En términos técnicos, ¿qué hace una VPN corporativa?","options":["Acelera notablemente tu conexión a internet fija","Cambia por completo tu navegador web","Tiende un túnel cifrado que te mete en la red privada","Duplica el ancho de banda de tu conexión"],"correctIndex":2,"feedback":{"correct":"Correcto. Estar dentro estando fuera: el acceso remoto que respeta la segmentación.","incorrect":"La VPN extiende la red privada a través de un túnel cifrado: tu equipo se comporta como si estuviera dentro, y el camino no lee nada."}}$j$),
  (4, 'quiz', $j${"variant":"multiple_choice","prompt":"Un anuncio promete que su VPN comercial te hace 'invisible y anónimo en internet'. La lectura técnica correcta es:","options":["Cierto: las VPN garantizan un anonimato total y absoluto","Cierto, pero solo si pagas la versión premium","Las VPN comerciales no cifran nada de nada","La confianza se mueve: el proveedor de la VPN ve tu salida"],"correctIndex":3,"feedback":{"correct":"Correcto. Útil contra el Wi-Fi hostil del aeropuerto; no es magia: es reubicar la confianza. Criterio sobre marketing.","incorrect":"La VPN comercial cifra el tramo hasta SU servidor — desde ahí, el proveedor ve tu salida. Protege del Wi-Fi local; no es anonimato mágico."}}$j$),
  (5, 'resumen', $j${"title":"Resumen — VPN","points":["VPN corporativa: túnel cifrado que te mete DENTRO de la red privada — IP interna, camino ilegible, cruce registrado.","El acceso remoto que respeta la segmentación: el técnico llega a expedientes sin abrir puertas nuevas.","El mismo túnel une sedes: un cable invisible entre edificios.","VPN comercial: misma tecnología, otro fin — protege del Wi-Fi local moviendo la confianza al proveedor.","No hay anonimato mágico: hay elección de en quién confiar."]}$j$)
) as v(ord, kind, payload)
where c.slug = 'redes-y-sistemas' and l.slug = 'm06-l05-vpn';

-- ═════════════════════════════════════════════════════════════════════
-- L06 · Wi-Fi: seguridad en el aire (+ nota ética)
-- ═════════════════════════════════════════════════════════════════════
insert into public.content_blocks (lesson_id, sort_order, kind, payload)
select l.id, v.ord, v.kind, v.payload::jsonb
from public.lessons l
join public.modules m on m.id = l.module_id
join public.courses c on c.id = m.course_id,
(values
  (1, 'texto', $j${"title":"El aire no tiene paredes","body":"El cable entrega su señal a UN destino; el Wi-Fi la GRITA en todas direcciones — cualquier antena en alcance recibe las ondas, incluida la del vecino y la del carro estacionado enfrente. Por eso el Wi-Fi necesita lo que el cable no: CIFRADO DE LA RED. El estándar vigente es WPA2, y el moderno WPA3 (elígelo si tu equipo lo ofrece); el viejo WEP está roto desde hace décadas — verlo activo es como ver Telnet: alarma. ¿Y una red ABIERTA, sin contraseña? Todo lo que no viaje cifrado por capas superiores queda legible para cualquier antena cercana. Las capas del módulo 2 te salvan a medias: HTTPS protege el CONTENIDO de cada conexión aunque la red sea hostil… pero los metadatos (a quién visitas, cuándo, cuánto) quedan a la vista. Completa la defensa doméstica: contraseña larga, WPA2/WPA3, y — la lección de este módulo — red de INVITADOS separada: la segmentación también vive en casa."}$j$),
  (2, 'nota_etica', $j${"title":"Escuchar el aire: solo el tuyo","body":"Que las ondas lleguen a tu antena no te da derecho a examinarlas. CAPTURAR o interceptar tráfico de redes AJENAS — el Wi-Fi del vecino, la red de una empresa, el aeropuerto — es DELITO en la mayoría de los países y una violación de la privacidad de personas concretas, aunque 'solo estés mirando' y aunque la red esté abierta. La regla profesional es absoluta: se captura tráfico ÚNICAMENTE en redes PROPIAS o con AUTORIZACIÓN ESCRITA del dueño (así trabajan los auditores de seguridad: contrato primero, captura después). En el próximo módulo usarás una herramienta real de captura — sobre TU propia red, que para eso es tuya. El poder técnico que estás adquiriendo viene con esta frontera clara: la curiosidad no es autorización."}$j$),
  (3, 'quiz', $j${"variant":"multiple_choice","prompt":"¿Por qué el Wi-Fi necesita cifrado de red (WPA2/WPA3) y el cable normalmente no?","options":["El aire es compartido: cualquier antena cercana recibe","Porque el Wi-Fi es una tecnología mucho más nueva","Porque el cable de red resulta más caro","Porque las ondas de radio viajan más lento"],"correctIndex":0,"feedback":{"correct":"Correcto. El Wi-Fi grita en todas direcciones: sin cifrado, cualquier antena cercana escucha.","incorrect":"Las ondas llegan a cualquier antena en alcance — vecinos incluidos. El cifrado de red (WPA2/WPA3) es la pared que el aire no tiene."}}$j$),
  (4, 'quiz', $j${"variant":"multiple_choice","prompt":"Navegas por HTTPS en una red Wi-Fi abierta (sin contraseña). ¿Qué queda protegido y qué queda expuesto?","options":["Todo queda protegido: con HTTPS es suficiente","El contenido va cifrado, pero los metadatos se ven","Nada se protege: HTTPS no funciona en Wi-Fi","Solo las fotos que envías quedan expuestas"],"correctIndex":1,"feedback":{"correct":"Correcto. Las capas se reparten el trabajo: TLS cifra la carta; la red abierta deja los sobres a la vista de todos.","incorrect":"HTTPS protege el contenido conexión por conexión; la red abierta expone los metadatos (destinos, horarios, volúmenes) a cualquier antena."}}$j$),
  (5, 'quiz', $j${"variant":"multiple_choice","prompt":"En términos legales y éticos, ¿cuándo es legítimo capturar tráfico de una red Wi-Fi?","options":["Siempre que la red esté completamente abierta","Cuando estás seguro de que nadie se dará cuenta","Solo en redes propias o con autorización escrita","Si es la red de un vecino al que conoces bien"],"correctIndex":2,"feedback":{"correct":"Correcto. La regla absoluta del oficio: red propia o contrato. La curiosidad no es autorización.","incorrect":"Red propia o autorización escrita — sin excepciones. Que las ondas lleguen a tu antena no te da derecho a examinarlas."}}$j$),
  (6, 'resumen', $j${"title":"Resumen — Wi-Fi","points":["El aire es un medio compartido sin paredes: cualquier antena en alcance escucha — por eso el Wi-Fi cifra la red.","WPA2 es el estándar, WPA3 el moderno; WEP está roto (alarma, como Telnet); red abierta = sobres a la vista.","HTTPS salva el contenido en redes hostiles; los metadatos quedan expuestos.","Defensa doméstica: contraseña larga + WPA2/WPA3 + red de invitados separada (segmentación en casa).","⚖️ Capturar tráfico: SOLO redes propias o autorización escrita — la frontera absoluta del oficio."]}$j$)
) as v(ord, kind, payload)
where c.slug = 'redes-y-sistemas' and l.slug = 'm06-l06-wifi';

-- ═════════════════════════════════════════════════════════════════════
-- X01 · Examen de región (jefe del módulo)
-- ═════════════════════════════════════════════════════════════════════
insert into public.content_blocks (lesson_id, sort_order, kind, payload)
select l.id, v.ord, v.kind, v.payload::jsonb
from public.lessons l
join public.modules m on m.id = l.module_id
join public.courses c on c.id = m.course_id,
(values
  (1, 'texto', $j${"title":"La sexta región","body":"Byte llegó a la región de la arquitectura: diez preguntas guardan el paso. Todo lo viviste: las VLANs y su regla de oro, el routing salto a salto, el vigilante del cruce, la clínica segmentada por zonas, los túneles cifrados y la seguridad del aire. Las preguntas que falles volverán al final hasta que las domines. Adelante."}$j$),
  (2, 'quiz', $j${"variant":"multiple_choice","prompt":"Una empresa quiere separar administración e invitados SIN comprar más switches ni recablear. La herramienta es:","options":["Comprando bastantes routers nuevos y más caros","Cambiando todas las contraseñas de la red","Apagando el Wi-Fi de toda la oficina","VLANs: redes lógicas dentro del mismo switch físico"],"correctIndex":3,"feedback":{"correct":"Correcto. Mismo hardware, fronteras de software: separar sin recablear.","incorrect":"Las VLANs crean redes lógicas separadas dentro del mismo switch: la segmentación sin gasto de hardware."}}$j$),
  (3, 'quiz', $j${"variant":"multiple_choice","prompt":"Dos VLANs conviven en el mismo switch. Para que un paquete cruce de una a otra necesita:","options":["Pasando por un router: su único puente es ese cruce","Nada especial: comparten el mismo aparato","Con un cable directo entre los dos puertos del switch","Reiniciando el switch cada cierto tiempo"],"correctIndex":0,"feedback":{"correct":"Correcto. La regla de oro — y la bendición de seguridad: todo cruce pasa por un punto vigilable.","incorrect":"Las VLANs no se hablan directo: el cruce exige router, y ese punto único es donde vive el control."}}$j$),
  (4, 'quiz', $j${"variant":"multiple_choice","prompt":"En el routing de internet, ¿quién conoce el camino COMPLETO de un paquete hasta su destino?","options":["El primer router calcula toda la ruta entera","Nadie: cada router decide solo el siguiente salto","Un servidor central que guarda todas las rutas","El navegador que hizo la petición original"],"correctIndex":1,"feedback":{"correct":"Correcto. Sin mapa ni dueño central: miles de decisiones locales, y resiliencia cuando un tramo cae.","incorrect":"Ningún router tiene el mapa completo: cada uno resuelve UN salto, y el viaje emerge de la cadena."}}$j$),
  (5, 'quiz', $j${"variant":"multiple_choice","prompt":"'Todo lo que no conozco, sale por esta puerta.' En la tabla de rutas de tu equipo, esa entrada y esa puerta son:","options":["La ruta secreta interna y el servidor DNS","El firewall de la red y el switch principal","La ruta por defecto y el gateway: cercano y lejano","La memoria caché y el servidor proxy"],"correctIndex":2,"feedback":{"correct":"Correcto. La puerta de enlace del módulo 1, con su papel técnico completo.","incorrect":"Es la ruta por defecto, apuntando al gateway: el 'todo lo demás' de toda tabla de rutas."}}$j$),
  (6, 'quiz', $j${"variant":"multiple_choice","prompt":"Un firewall bien configurado sigue el principio de 'denegar por defecto'. Esto significa que:","options":["Bloquea absolutamente todo el tráfico, siempre","Deniega solamente el tráfico que parece sospechoso","Le pregunta al usuario en cada conexión nueva","Solo lo explícitamente permitido; el resto se bloquea"],"correctIndex":3,"feedback":{"correct":"Correcto. Lista corta de permitidos pensados; muro para el resto.","incorrect":"Denegar por defecto: nada cruza sin regla que lo permita. La versión de red del mínimo privilegio."}}$j$),
  (7, 'quiz', $j${"variant":"multiple_choice","prompt":"¿Por qué un firewall NO protege contra un correo de phishing que el empleado abre voluntariamente?","options":["El firewall filtra puertos, no intenciones: el canal era legal","Porque los firewalls no llegan a ver el contenido de los correos","Porque el phishing es una actividad legal","Porque el firewall estaba puesto en otra VLAN"],"correctIndex":0,"feedback":{"correct":"Correcto. Canales legítimos, contenido malicioso: eso lo cazan otras capas (criterio, permisos, logs).","incorrect":"El tráfico del phishing viaja por puertas permitidas (correo, web): el vigilante de puertas no lee intenciones. Capas."}}$j$),
  (8, 'quiz', $j${"variant":"multiple_choice","prompt":"En una red segmentada, el servidor web público vive en la DMZ. Si un atacante lo compromete, el diseño garantiza que:","options":["Toda la red de la empresa cae junto con él","Queda atrapado en una isla: sin rutas hacia lo interno","El atacante obtiene todos los expedientes internos","Se apaga por completo el internet de la oficina"],"correctIndex":1,"feedback":{"correct":"Correcto. La DMZ diseña PARA la caída: expuesto ≠ conectado a la joya de la corona.","incorrect":"La DMZ existe para eso: si lo expuesto cae, el atacante no encuentra puente hacia las zonas internas."}}$j$),
  (9, 'quiz', $j${"variant":"multiple_choice","prompt":"Un técnico trabaja desde casa y necesita entrar a un servidor que solo acepta conexiones de la red interna. La solución correcta es:","options":["Abrir el servidor por completo a todo internet","Enviarse a sí mismo los archivos por correo","Una VPN corporativa: túnel cifrado con IP interna","Usar sin permiso la red del vecino de al lado"],"correctIndex":2,"feedback":{"correct":"Correcto. Estar dentro estando fuera: el túnel autenticado, cifrado y registrado.","incorrect":"La VPN extiende la red privada hasta su casa: llega al servidor SIN abrirle puertas nuevas al mundo."}}$j$),
  (10, 'quiz', $j${"variant":"multiple_choice","prompt":"De estas configuraciones de Wi-Fi, ¿cuál es la correcta hoy y cuál es una alarma?","options":["WEP es la correcta; WPA3 debería dar la alarma","Red abierta es correcta; el resto da alarma","Todas dan igual mientras haya buena contraseña","WPA2/WPA3 bien; WEP o red abierta = alarma"],"correctIndex":3,"feedback":{"correct":"Correcto. WPA2 estándar, WPA3 moderno; WEP y las redes abiertas dejan el aire legible.","incorrect":"El vigente es WPA2 (o WPA3, mejor). WEP está roto y la red abierta grita en claro: ambas son alarmas."}}$j$),
  (11, 'quiz', $j${"variant":"multiple_choice","prompt":"Pregunta final de entrevista: 'te encargan diseñar desde cero la red de una clínica nueva — ¿por dónde empiezas?' Tu respuesta senior:","options":["Por zonas de confianza, un firewall en cada cruce, y registro","Comprando directamente el router más caro del mercado","Eligiendo bien el color de cada uno de los cables","Instalando un antivirus en absolutamente todos los equipos"],"correctIndex":0,"feedback":{"correct":"Impecable. Arquitectura antes que hardware: zonas por confianza, cruce único vigilado, denegar por defecto, anotar todo. El plano de la clínica — y de casi toda red seria.","incorrect":"La respuesta senior diseña primero: zonas por nivel de confianza, firewall en cada cruce (denegar por defecto), DMZ para lo expuesto, invitados aislados y logs en el cruce. Los aparatos vienen después."}}$j$)
) as v(ord, kind, payload)
where c.slug = 'redes-y-sistemas' and l.slug = 'm06-x01-examen';
